<?php
namespace App\Services\Admin;
use App\Models\{Seat,SeatHold,TravelSchedule}; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class SeatService { public function releaseExpiredHolds(): int { return SeatHold::where('expires_at','<=',now())->delete(); } public function availability(TravelSchedule $schedule): array { $this->releaseExpiredHolds(); $booked=DB::table('booking_seat')->where('travel_schedule_id',$schedule->id)->pluck('seat_id')->all(); $held=SeatHold::where('travel_schedule_id',$schedule->id)->pluck('seat_id')->all(); return $schedule->seatLayout->seats()->orderBy('row_number')->orderBy('column_number')->get()->map(fn($s)=>['id'=>$s->id,'seat_number'=>$s->seat_number,'is_blocked'=>$s->is_blocked,'is_booked'=>in_array($s->id,$booked),'is_held'=>in_array($s->id,$held)])->all(); } public function hold(TravelSchedule $schedule, array $seatIds, ?int $userId=null): string { return DB::transaction(function() use($schedule,$seatIds,$userId){ $this->releaseExpiredHolds(); $this->validateAvailable($schedule,$seatIds); $token=(string) str()->uuid(); foreach($seatIds as $seatId) SeatHold::create(['travel_schedule_id'=>$schedule->id,'seat_id'=>$seatId,'user_id'=>$userId,'token'=>$token,'expires_at'=>now()->addMinutes(15)]); return $token; }); } public function validateAvailable(TravelSchedule $schedule, array $seatIds, ?string $holdToken=null): void { $seatIds=array_values(array_unique($seatIds)); if(empty($seatIds)) throw ValidationException::withMessages(['seat_ids'=>'Select at least one seat.']); $valid=Seat::where('seat_layout_id',$schedule->seat_layout_id)->whereIn('id',$seatIds)->where('is_blocked',false)->count(); if($valid !== count($seatIds)) throw ValidationException::withMessages(['seat_ids'=>'One or more seats are invalid or blocked.']); $booked=DB::table('booking_seat')->where('travel_schedule_id',$schedule->id)->whereIn('seat_id',$seatIds)->exists(); if($booked) throw ValidationException::withMessages(['seat_ids'=>'One or more seats are already booked.']); $holds=SeatHold::where('travel_schedule_id',$schedule->id)->whereIn('seat_id',$seatIds)->when($holdToken,fn($q)=>$q->where('token','!=',$holdToken))->exists(); if($holds) throw ValidationException::withMessages(['seat_ids'=>'One or more seats are temporarily held.']); } public function consumeHold(TravelSchedule $schedule, array $seatIds, ?string $token): void { if(!$token) return; SeatHold::where('travel_schedule_id',$schedule->id)->where('token',$token)->whereIn('seat_id',$seatIds)->delete(); } }
